import React, { useState, useEffect, useRef, useCallback } from "react";
import api from "../api/axiosInstance";
import { getSensorByUser } from "../api/sensorsapi";

// ─── KPI API calls ──────────────────────────────────────────────────────────
const createKPI = (payload) =>
  api.post("/api/KPIs", {
    KPIName: payload.name,
    KPIFormula: payload.formula,
    Frequency: payload.frequency || "5min",
  });

const fetchKPIs = () => api.get("/api/KPIs");
const fetchKPILatest = (kpiId) => api.get(`/api/KPIs/${kpiId}/latest`);

// ─── Utilities ───────────────────────────────────────────────────────────────
const FREQ_MS = {
  "1min": 60_000,    "5min": 300_000,    "15min": 900_000,
  "30min": 1_800_000,"1hr": 3_600_000,   "6hr": 21_600_000,
  "12hr": 43_200_000,"24hr": 86_400_000,
};
const freqToMs = (f) => FREQ_MS[f] ?? 300_000;

const formatCountdown = (secs) => {
  if (secs >= 3600) return `${Math.floor(secs / 3600)}h ${Math.floor((secs % 3600) / 60)}m`;
  if (secs >= 60)   return `${Math.floor(secs / 60)}m ${secs % 60}s`;
  return `${secs}s`;
};

const formatRelTime = (date) => {
  if (!date) return null;
  const diff = Math.round((Date.now() - date) / 1000);
  if (diff < 5)    return "just now";
  if (diff < 60)   return `${diff}s ago`;
  if (diff < 3600) return `${Math.floor(diff / 60)}m ago`;
  return `${Math.floor(diff / 3600)}h ago`;
};

/**
 * Pulls a numeric value out of whatever shape the backend returns.
 * Supports: { value }, { kpiValue }, { latestValue }, plain number, array[0]
 */
const parseApiValue = (raw) => {
  const candidate =
    raw?.value ?? raw?.kpiValue ?? raw?.kpi_value ?? raw?.latestValue ??
    raw?.latest_value ?? raw?.result ??
    (Array.isArray(raw) && raw.length > 0
      ? (raw[0]?.value ?? raw[0]?.kpiValue ?? raw[0])
      : undefined) ??
    (typeof raw === "number" ? raw : null);
  if (candidate === null || candidate === undefined || isNaN(parseFloat(candidate))) return null;
  return Number(parseFloat(candidate).toFixed(2));
};

// ─── Formula evaluator ──────────────────────────────────────────────────────
const evaluateFormula = (formulaStr, latestValues) => {
  if (!formulaStr?.trim()) return null;
  try {
    let expr = formulaStr.replace(/sensor_(\d+)/gi, (_, id) => {
      const v = latestValues[`sensor_${id}`] ?? latestValues[`sensor_${id}`.toUpperCase()];
      return v !== undefined ? v : "NaN";
    });
    expr = expr
      .replace(/AVG\(([^)]+)\)/gi,   (_, a) => { const ns = a.split(",").map(Number).filter((n) => !isNaN(n)); return ns.length ? ns.reduce((s, v) => s + v, 0) / ns.length : 0; })
      .replace(/SUM\(([^)]+)\)/gi,   (_, a) => a.split(",").map(Number).filter((n) => !isNaN(n)).reduce((s, v) => s + v, 0))
      .replace(/MAX\(([^)]+)\)/gi,   (_, a) => Math.max(...a.split(",").map(Number).filter((n) => !isNaN(n))))
      .replace(/MIN\(([^)]+)\)/gi,   (_, a) => Math.min(...a.split(",").map(Number).filter((n) => !isNaN(n))))
      .replace(/COUNT\(([^)]+)\)/gi, (_, a) => a.split(",").map(Number).filter((n) => !isNaN(n)).length);
    // eslint-disable-next-line no-new-func
    const r = Function('"use strict"; return (' + expr + ')')();
    return isNaN(r) || !isFinite(r) ? null : Number(r).toFixed(2);
  } catch { return null; }
};

// ─── Simulated trend fallback (used before enough real history exists) ────────
const genTrendData = (baseVal, range) => {
  const counts = { "1h": 12, "6h": 24, "24h": 24, "7d": 7, "30d": 30 };
  const n = counts[range] || 24;
  const b = parseFloat(baseVal) || 50;
  return Array.from({ length: n }, () => +(b + (Math.random() - 0.5) * b * 0.15).toFixed(2));
};

const getTrendLabels = (range, count) => {
  const cfg = {
    "1h":  (i, n) => `-${(n - i) * 5}m`,
    "6h":  (i, n) => `-${(n - i) * 15}m`,
    "24h": (i, n) => `-${n - i}h`,
    "7d":  (i)    => ["Mon","Tue","Wed","Thu","Fri","Sat","Sun"][i % 7],
    "30d": (i)    => `Day ${i + 1}`,
  };
  const fn = cfg[range] ?? cfg["24h"];
  return Array.from({ length: count }, (_, i) => fn(i, count));
};

// ─── Constants ──────────────────────────────────────────────────────────────
const ICON_MAP = {
  availability: "bi-check2-circle", performance: "bi-speedometer2",
  quality: "bi-award", oee: "bi-graph-up", downtime: "bi-clock-history",
};
const COLOR_MAP    = ["#00c6ae","#0f8fd4","#7b5ea7","#f39c12","#e74c3c","#2ecc71","#e91e63"];
const FX_FUNCS     = ["SUM", "AVG", "MAX", "MIN", "COUNT"];
const FREQUENCIES  = ["1min","5min","15min","30min","1hr","6hr","12hr","24hr"];
const TREND_RANGES = ["1h","6h","24h","7d","30d"];
const MAX_HISTORY  = 120; // accumulate up to 120 real readings per KPI

// ─── TrendChart canvas ───────────────────────────────────────────────────────
const TrendChart = ({ data, color, labels }) => {
  const ref = useRef(null);
  useEffect(() => {
    const canvas = ref.current;
    if (!canvas || !data.length) return;
    const ctx = canvas.getContext("2d");
    const W = canvas.width, H = canvas.height;
    const PL = 42, PR = 10, PT = 12, PB = 28;
    const pw = W - PL - PR, ph = H - PT - PB;
    const min = Math.min(...data), max = Math.max(...data), rng = max - min || 1;
    ctx.clearRect(0, 0, W, H);
    ctx.font = "9px monospace"; ctx.textAlign = "right"; ctx.fillStyle = "rgba(150,150,150,0.8)";
    for (let i = 0; i <= 4; i++) {
      const val = min + (rng * i) / 4, y = PT + ph - (ph * i) / 4;
      ctx.strokeStyle = "rgba(150,150,150,0.15)"; ctx.lineWidth = 1;
      ctx.beginPath(); ctx.moveTo(PL, y); ctx.lineTo(PL + pw, y); ctx.stroke();
      ctx.fillText(val.toFixed(1), PL - 4, y + 3);
    }
    const xTicks = Math.min(5, data.length - 1);
    ctx.textAlign = "center"; ctx.fillStyle = "rgba(150,150,150,0.8)";
    for (let i = 0; i <= xTicks; i++) {
      const idx = Math.round((i / xTicks) * (data.length - 1));
      const x = PL + (idx / (data.length - 1)) * pw;
      ctx.fillText(labels[idx] || "", x, H - 6);
      ctx.strokeStyle = "rgba(150,150,150,0.25)"; ctx.beginPath(); ctx.moveTo(x, PT); ctx.lineTo(x, PT + ph); ctx.stroke();
    }
    ctx.strokeStyle = "rgba(150,150,150,0.35)"; ctx.lineWidth = 1;
    ctx.beginPath(); ctx.moveTo(PL, PT); ctx.lineTo(PL, PT + ph); ctx.lineTo(PL + pw, PT + ph); ctx.stroke();
    ctx.beginPath();
    data.forEach((v, i) => {
      const x = PL + (i / (data.length - 1)) * pw;
      const y = PT + ph - ((v - min) / rng) * ph;
      i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
    });
    ctx.strokeStyle = color; ctx.lineWidth = 2; ctx.lineJoin = "round"; ctx.stroke();
    ctx.lineTo(PL + pw, PT + ph); ctx.lineTo(PL, PT + ph); ctx.closePath();
    ctx.fillStyle = color + "22"; ctx.fill();
    const lv = data[data.length - 1];
    const dx = PL + pw, dy = PT + ph - ((lv - min) / rng) * ph;
    ctx.beginPath(); ctx.arc(dx, dy, 3.5, 0, Math.PI * 2); ctx.fillStyle = color; ctx.fill();
  }, [data, color, labels]);
  return <canvas ref={ref} width={460} height={180} style={{ display: "block", width: "100%", height: 180 }} />;
};

// ─── TrendPopup ──────────────────────────────────────────────────────────────
/**
 * HOW MIN / MAX / AVG IS CALCULATED
 * ──────────────────────────────────
 * kpi._history = array of real numeric values accumulated over the session
 *   by the auto-refresh poller (each call to /api/KPIs/{id}/latest appends one value).
 *
 * If _history has ≥ 3 real points  → use those for chart + stats (real values).
 * If _history has < 3 points (e.g. just loaded) → fall back to genTrendData,
 *   which simulates ±7.5% jitter around the current live value.
 *
 * So: the longer the page stays open, the more accurate min/max/avg become.
 * At "5min" frequency you get 12 real points per hour; at "1min" you get 60.
 */
const TrendPopup = ({ kpi, onClose }) => {
  const [range, setRange] = useState("24h");
  const realHistory = kpi._history ?? [];
  const isReal = realHistory.length >= 3;

  // Use real accumulated history when available, else simulate
  const chartData = isReal ? realHistory.slice(-60) : genTrendData(kpi._liveVal, range);
  const labels    = getTrendLabels(range, chartData.length);

  const min = chartData.length ? Math.min(...chartData).toFixed(2) : "—";
  const max = chartData.length ? Math.max(...chartData).toFixed(2) : "—";
  const avg = chartData.length ? (chartData.reduce((s, v) => s + v, 0) / chartData.length).toFixed(2) : "—";

  return (
    <div style={{ position:"fixed", inset:0, zIndex:2000, background:"rgba(0,0,0,0.45)", display:"flex", alignItems:"center", justifyContent:"center", padding:16 }} onClick={onClose}>
      <div style={{ width:"100%", maxWidth:520, background:"var(--sb-white)", border:"1px solid var(--sb-border)", borderRadius:20, padding:24, boxShadow:"0 24px 64px rgba(0,0,0,0.18)" }} onClick={(e) => e.stopPropagation()}>

        {/* Header */}
        <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:16 }}>
          <div style={{ display:"flex", alignItems:"center", gap:10 }}>
            <div style={{ width:32, height:32, borderRadius:8, background:kpi.color+"22", display:"flex", alignItems:"center", justifyContent:"center" }}>
              <i className={`bi ${kpi.icon}`} style={{ color:kpi.color, fontSize:"1rem" }} />
            </div>
            <div>
              <div style={{ fontSize:14, fontWeight:700, color:"var(--sb-text)" }}>{kpi.name}</div>
              <div style={{ fontSize:11, color:"var(--sb-muted)", display:"flex", alignItems:"center", gap:5 }}>
                Trend Analysis
                {isReal
                  ? <span style={{ background:"#00c6ae18", color:"#00c6ae", padding:"1px 7px", borderRadius:10, fontSize:10, fontWeight:700 }}>● Live — {realHistory.length} readings</span>
                  : <span style={{ background:"#f39c1218", color:"#f39c12", padding:"1px 7px", borderRadius:10, fontSize:10, fontWeight:700 }}>⚬ Accumulating real data…</span>
                }
              </div>
            </div>
          </div>
          <button onClick={onClose} style={{ background:"var(--sb-light-bg)", border:"1px solid var(--sb-border)", borderRadius:8, width:30, height:30, display:"flex", alignItems:"center", justifyContent:"center", cursor:"pointer", color:"var(--sb-muted)", fontSize:16 }}>×</button>
        </div>

        {/* Live value */}
        <div style={{ display:"flex", alignItems:"baseline", gap:6, marginBottom:14, padding:"10px 14px", background:kpi.color+"10", borderRadius:10, border:`1px solid ${kpi.color}30` }}>
          <span style={{ fontSize:28, fontWeight:800, color:kpi.color, lineHeight:1 }}>{kpi._liveVal ?? "—"}</span>
          {kpi.unit && <span style={{ fontSize:13, color:"var(--sb-muted)" }}>{kpi.unit}</span>}
          <span style={{ marginLeft:"auto", fontSize:11, color:"var(--sb-muted)", fontFamily:"monospace" }}>fx: {kpi.formula}</span>
        </div>

        {/* Range selector — only useful for simulated data */}
        {!isReal && (
          <div style={{ display:"flex", gap:6, marginBottom:12 }}>
            {TREND_RANGES.map((r) => (
              <button key={r} onClick={() => setRange(r)} style={{ flex:1, fontSize:11, padding:"5px 0", borderRadius:8, fontWeight:700, cursor:"pointer", border:"1px solid", transition:"all 0.15s", background:range===r?kpi.color:"var(--sb-light-bg)", color:range===r?"#fff":"var(--sb-muted)", borderColor:range===r?kpi.color:"var(--sb-border)" }}>{r}</button>
            ))}
          </div>
        )}

        {/* Chart */}
        <div style={{ borderRadius:12, overflow:"hidden", background:"var(--sb-light-bg)", border:"1px solid var(--sb-border)", padding:"10px 8px 6px" }}>
          <TrendChart data={chartData} color={kpi.color} labels={labels} />
        </div>

        {/* Min / Avg / Max — real values when history available */}
        <div style={{ display:"flex", justifyContent:"space-between", marginTop:12, padding:"10px 14px", background:"var(--sb-light-bg)", borderRadius:10, border:"1px solid var(--sb-border)" }}>
          {[["Min", min, "var(--sb-text)"], ["Avg", avg, kpi.color], ["Max", max, "var(--sb-text)"]].map(([label, val, col]) => (
            <div key={label} style={{ textAlign:"center" }}>
              <div style={{ fontSize:10, color:"var(--sb-muted)", fontWeight:600, textTransform:"uppercase", letterSpacing:"0.5px" }}>{label}</div>
              <div style={{ fontSize:16, fontWeight:800, color:col, marginTop:2 }}>{val}</div>
              <div style={{ fontSize:9, color:"var(--sb-muted)", marginTop:1 }}>{isReal ? "real" : "est."}</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

// ─── KPI Card ────────────────────────────────────────────────────────────────
const KPICard = ({ kpi, lastRefreshed, isRefreshing }) => {
  const [showTrend, setShowTrend] = useState(false);
  const [relTime, setRelTime]     = useState(() => formatRelTime(lastRefreshed));

  useEffect(() => {
    setRelTime(formatRelTime(lastRefreshed));
    const t = setInterval(() => setRelTime(formatRelTime(lastRefreshed)), 10_000);
    return () => clearInterval(t);
  }, [lastRefreshed]);

  const val    = kpi._liveVal;
  const noData = val === null || val === undefined || !kpi.formula?.trim();
  const errorMessage = !kpi.formula?.trim()
    ? "No formula configured yet."
    : val === null
    ? "Unable to compute — verify formula or sensor connection."
    : null;

  return (
    <>
      <div
        style={{ background:noData?"linear-gradient(135deg,rgba(229,62,62,0.07),rgba(252,235,235,0.6))":"var(--sb-card-bg)", borderRadius:16, border:noData?"1.5px solid #e53e3e":"1px solid var(--sb-border)", padding:20, position:"relative", overflow:"visible", transition:"transform 0.2s, box-shadow 0.2s" }}
        onMouseEnter={(e) => { if (!noData) { e.currentTarget.style.transform="translateY(-3px)"; e.currentTarget.style.boxShadow="0 12px 32px rgba(0,0,0,0.08)"; } }}
        onMouseLeave={(e) => { e.currentTarget.style.transform=""; e.currentTarget.style.boxShadow=""; }}
      >
        <div style={{ position:"absolute", top:0, left:0, right:0, height:3, background:noData?"#e53e3e":kpi.color, borderRadius:"16px 16px 0 0" }} />

        {/* Refresh pulse indicator */}
        {isRefreshing && !noData && (
          <div style={{ position:"absolute", top:10, left:12, width:6, height:6, borderRadius:"50%", background:"#00c6ae", animation:"pulseDot 0.8s infinite" }} />
        )}

        <div onClick={() => { if (!noData) setShowTrend(true); }} title={noData?undefined:"Click for trend"}
          style={{ position:"absolute", top:16, right:16, width:38, height:38, borderRadius:10, background:noData?"rgba(229,62,62,0.12)":kpi.color+"18", display:"flex", alignItems:"center", justifyContent:"center", cursor:noData?"default":"pointer", transition:"background 0.15s", fontSize:"1.1rem" }}>
          <i className={`bi ${kpi.icon}`} style={{ color:noData?"#e53e3e":kpi.color }} />
        </div>

        <div style={{ paddingRight:52 }}>
          <p style={{ fontSize:"0.75rem", fontWeight:700, color:"var(--sb-muted)", marginBottom:6, textTransform:"uppercase", letterSpacing:"0.5px" }}>{kpi.name}</p>

          {noData ? (
            <div style={{ display:"flex", alignItems:"center", gap:6, marginBottom:8 }}>
              <i className="bi bi-exclamation-triangle-fill" style={{ color:"#e53e3e", fontSize:"1.1rem" }} />
              <span style={{ fontSize:"0.75rem", color:"#e53e3e", fontWeight:600, lineHeight:1.3 }}>{errorMessage}</span>
            </div>
          ) : (
            <div style={{ display:"flex", alignItems:"baseline", gap:4, marginBottom:8 }}>
              <span style={{ fontSize:"2.2rem", fontWeight:800, lineHeight:1, color:kpi.color, letterSpacing:"-1px" }}>{val}</span>
              {kpi.unit && <span style={{ fontSize:"0.82rem", color:"var(--sb-muted)", fontWeight:500 }}>{kpi.unit}</span>}
            </div>
          )}

          <div style={{ display:"inline-flex", alignItems:"center", gap:6, padding:"3px 10px", borderRadius:6, background:"var(--sb-light-bg)", border:"1px solid var(--sb-border)", maxWidth:"100%", overflow:"hidden" }}>
            <span style={{ fontSize:"0.65rem", fontWeight:800, color:kpi.color }}>fx</span>
            <span style={{ fontSize:"0.68rem", fontFamily:"monospace", color:"var(--sb-muted)", overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }} title={kpi.formula||"No formula"}>
              {kpi.formula ? (kpi.formula.length>24 ? kpi.formula.slice(0,24)+"…" : kpi.formula) : "—"}
            </span>
          </div>

          {!noData && relTime && (
            <div style={{ marginTop:7, fontSize:"0.63rem", color:"var(--sb-muted)" }}>
              <i className="bi bi-clock me-1" />Updated {relTime}
              {(kpi._history?.length ?? 0) > 0 &&
                <span style={{ marginLeft:6, color:"var(--sb-accent)", fontWeight:600 }}>· {kpi._history.length} readings</span>}
            </div>
          )}
          {!noData && <div style={{ marginTop:4, fontSize:"0.63rem", color:"var(--sb-muted)", fontStyle:"italic" }}><i className="bi bi-graph-up me-1" style={{ color:kpi.color }} />Click icon for trend</div>}
          {noData && <div style={{ marginTop:8 }}><span style={{ fontSize:"0.65rem", background:"#fee2e2", color:"#b91c1c", padding:"2px 8px", borderRadius:20, fontWeight:700 }}>⚠ No data</span></div>}
        </div>
      </div>
      {showTrend && <TrendPopup kpi={kpi} onClose={() => setShowTrend(false)} />}
    </>
  );
};

// ─── KPIManagement ──────────────────────────────────────────────────────────
const KPIManagement = () => {
  const userId = localStorage.getItem("sb_userId");

  // Core data
  const [kpis, setKpis]                       = useState([]);
  const [loadingKpis, setLoadingKpis]         = useState(true);
  const [kpiLatestValues, setKpiLatestValues] = useState({});

  /**
   * kpiHistory: { [kpiId]: number[] }
   * Each number is a real value returned by /api/KPIs/{id}/latest.
   * Accumulated every auto-refresh cycle.
   * Used to compute real min/max/avg in TrendPopup over time.
   */
  const [kpiHistory, setKpiHistory]   = useState({});
  const kpiHistoryRef                 = useRef({});   // mutable mirror — no extra re-renders
  const kpisRef                       = useRef([]);   // latest kpis snapshot for intervals

  // Refresh control
  const [refreshFreq, setRefreshFreq]     = useState("5min");
  const [countdown, setCountdown]         = useState(null);
  const [isRefreshing, setIsRefreshing]   = useState(false);
  const [lastRefreshed, setLastRefreshed] = useState(null);

  // Form / UI
  const [showForm, setShowForm]         = useState(false);
  const [saving, setSaving]             = useState(false);
  const [form, setForm]                 = useState({ name:"", formula:"", unit:"", frequency:"5min", icon:"bi-graph-up", color:"#00c6ae" });
  const [errors, setErrors]             = useState({});
  const [successMsg, setSuccessMsg]     = useState("");
  const [errMsg, setErrMsg]             = useState("");
  const [sensors, setSensors]           = useState([]);
  const [sensorSearch, setSensorSearch] = useState("");
  const [kpiSearch, setKpiSearch]       = useState("");
  const [showCalc, setShowCalc]         = useState(false);

  useEffect(() => { kpisRef.current = kpis; }, [kpis]);

  // ── Full load (initial + after creating new KPI) ───────────────────────────
  const loadKPIs = async () => {
    if (!userId) { setLoadingKpis(false); return; }
    setLoadingKpis(true);
    try {
      const res  = await fetchKPIs();
      const data = Array.isArray(res.data) ? res.data : res.data?.data ?? [];
      const mapped = data.map((k, i) => ({
        id: k.kpiId, name: k.kpiName, formula: k.kpiFormula, frequency: k.frequency,
        isActive: k.isActive, createdAt: k.createdAt,
        icon: ICON_MAP[k.kpiName?.toLowerCase()] || "bi-graph-up",
        color: COLOR_MAP[i % COLOR_MAP.length], unit: "", fromApi: true,
      }));
      setKpis(mapped);

      const settled = await Promise.allSettled(
        mapped.map((k) => fetchKPILatest(k.id).then((r) => ({ id: k.id, data: r.data })))
      );
      const entries = settled.map((result, i) => {
        const kpiId = mapped[i].id;
        if (result.status === "rejected") {
          const isNoResults = result.reason?.response?.data?.detail === "No results found for this KPI." || result.reason?.response?.status === 404;
          if (!isNoResults) console.warn(`KPI latest failed for ${kpiId}:`, result.reason?.response?.data || result.reason?.message);
          return [kpiId, null];
        }
        const num = parseApiValue(result.value.data);
        if (num !== null) {
          if (!kpiHistoryRef.current[kpiId]) kpiHistoryRef.current[kpiId] = [];
          kpiHistoryRef.current[kpiId].push(num);
        }
        return [kpiId, num];
      });
      setKpiLatestValues(Object.fromEntries(entries));
      setKpiHistory({ ...kpiHistoryRef.current });
      setLastRefreshed(new Date());
    } catch (e) {
      setErrMsg(e?.response?.data?.message || "Failed to load KPIs.");
      setTimeout(() => setErrMsg(""), 4000);
    } finally { setLoadingKpis(false); }
  };

  useEffect(() => { loadKPIs(); }, [userId]);

  // ── Lightweight background refresh — only re-polls /latest ─────────────────
  /**
   * Does NOT reset the full loading state — runs silently in the background.
   * On each call:
   *   1. Calls GET /api/KPIs/{id}/latest for every KPI in parallel
   *   2. Updates kpiLatestValues (triggers card re-render with new value)
   *   3. Pushes value into kpiHistoryRef[kpiId] (capped at MAX_HISTORY)
   *   4. Copies ref → kpiHistory state so TrendPopup sees updated data
   *   5. Updates lastRefreshed timestamp
   */
  const refreshLatestValues = useCallback(async () => {
    const currentKpis = kpisRef.current;
    if (!currentKpis.length) return;
    setIsRefreshing(true);
    try {
      const settled = await Promise.allSettled(
        currentKpis.map((k) => fetchKPILatest(k.id).then((r) => ({ id: k.id, data: r.data })))
      );
      const newVals = {};
      settled.forEach((result, i) => {
        const kpiId = currentKpis[i].id;
        if (result.status === "rejected") { newVals[kpiId] = kpiHistoryRef.current[kpiId]?.slice(-1)[0] ?? null; return; }
        const num = parseApiValue(result.value.data);
        newVals[kpiId] = num;
        if (num !== null) {
          if (!kpiHistoryRef.current[kpiId]) kpiHistoryRef.current[kpiId] = [];
          kpiHistoryRef.current[kpiId].push(num);
          if (kpiHistoryRef.current[kpiId].length > MAX_HISTORY)
            kpiHistoryRef.current[kpiId].shift();
        }
      });
      setKpiLatestValues((prev) => ({ ...prev, ...newVals }));
      setKpiHistory({ ...kpiHistoryRef.current });
      setLastRefreshed(new Date());
    } finally { setIsRefreshing(false); }
  }, []);

  // ── Auto-refresh: countdown ticker + API poll ──────────────────────────────
  /**
   * Single setInterval running every 1 second:
   *   - Decrements countdown by 1
   *   - When countdown reaches 0 → fires refreshLatestValues() + resets to totalSecs
   * Restarts cleanly whenever refreshFreq changes (useEffect cleanup clears old interval).
   */
  useEffect(() => {
    const totalSecs = Math.round(freqToMs(refreshFreq) / 1000);
    setCountdown(totalSecs);
    const tick = setInterval(() => {
      setCountdown((prev) => {
        if (prev <= 1) { refreshLatestValues(); return totalSecs; }
        return prev - 1;
      });
    }, 1000);
    return () => clearInterval(tick);
  }, [refreshFreq, refreshLatestValues]);

  // ── Sensors ───────────────────────────────────────────────────────────────
  useEffect(() => {
    const load = async () => {
      if (!userId) return;
      try {
        const res  = await getSensorByUser(userId);
        const list = Array.isArray(res.data) ? res.data : res.data?.data ?? [];
        setSensors(list.map((s) => ({ id:s.sensorId??s.id, name:s.sensorName??s.name, quantity:s.quantity, unit:s.unit })));
      } catch (e) { console.error("Sensor API failed:", e?.response?.status, e?.response?.data || e.message); }
    };
    load();
  }, [userId]);

  // ── Formula helpers ────────────────────────────────────────────────────────
  const insertToFormula  = (text) => setForm((f) => ({ ...f, formula: f.formula + text }));
  const insertFunction   = (fn)   => setForm((f) => ({ ...f, formula: f.formula + `${fn}(` }));
  const backspaceFormula = ()     => setForm((f) => ({ ...f, formula: f.formula.trimEnd().replace(/.$/, "") }));

  // ── Add KPI ───────────────────────────────────────────────────────────────
  const handleAddKpi = async () => {
    const errs = {};
    if (!form.name.trim())    errs.name    = "KPI name is required.";
    if (!form.formula.trim()) errs.formula = "Formula is required.";
    if (Object.keys(errs).length) { setErrors(errs); return; }
    setSaving(true);
    try {
      await createKPI(form);
      setForm({ name:"", formula:"", unit:"", frequency:"5min", icon:"bi-graph-up", color:"#00c6ae" });
      setShowForm(false); setSensorSearch(""); setErrors({}); setShowCalc(false);
      setSuccessMsg(`KPI "${form.name}" created successfully!`);
      setTimeout(() => setSuccessMsg(""), 3500);
      await loadKPIs();
    } catch (e) {
      setErrMsg(e?.response?.data?.message || "Failed to create KPI.");
      setTimeout(() => setErrMsg(""), 4000);
    } finally { setSaving(false); }
  };

  // ── Enrich KPIs ───────────────────────────────────────────────────────────
  const enrichedKpis = kpis.map((k) => {
    const latest = kpiLatestValues[k.id];
    return { ...k, _liveVal: latest !== null && latest !== undefined ? String(latest) : null, _history: kpiHistory[k.id] ?? [] };
  });

  const filteredKpis    = enrichedKpis.filter((k) => k.name.toLowerCase().includes(kpiSearch.toLowerCase()));
  const filteredSensors = sensors.filter((s) => s.name?.toLowerCase().includes(sensorSearch.toLowerCase()));

  // ── Render ────────────────────────────────────────────────────────────────
  return (
    <div>
      <style>{`
        @keyframes pulseDot { 0%,100%{opacity:1;transform:scale(1)} 50%{opacity:0.4;transform:scale(0.7)} }
        @keyframes spin      { to { transform:rotate(360deg); } }
        @keyframes calcSlideIn { from{opacity:0;transform:translateY(-6px) scale(0.97)} to{opacity:1;transform:translateY(0) scale(1)} }
        .fn-btn { padding:4px 11px;border-radius:20px;border:1px solid var(--sb-border);background:var(--sb-light-bg);color:var(--sb-accent);font-size:0.76rem;font-weight:700;cursor:pointer;font-family:monospace;transition:background 0.15s;white-space:nowrap; }
        .fn-btn:hover { background:var(--sb-accent);color:#fff;border-color:var(--sb-accent); }
        .sensor-chip { display:inline-flex;align-items:center;gap:5px;padding:3px 10px;border-radius:20px;background:var(--sb-light-bg);border:1px solid var(--sb-border);color:var(--sb-text);font-size:0.74rem;font-weight:600;cursor:pointer;transition:all 0.15s;white-space:nowrap; }
        .sensor-chip:hover { background:var(--sb-accent);color:#fff;border-color:var(--sb-accent); }
        .fx-bar { display:flex;align-items:center;background:var(--sb-light-bg);border:1.5px solid var(--sb-border);border-radius:8px;padding:6px 12px;transition:border-color 0.2s; }
        .fx-bar:focus-within { border-color:var(--sb-accent);background:var(--sb-white); }
        .fx-bar input { flex:1;background:none;border:none;outline:none;color:var(--sb-text);font-family:monospace;font-size:0.88rem; }
        .kpi-modal-overlay { position:fixed;inset:0;background:rgba(0,0,0,0.45);display:flex;align-items:center;justify-content:center;z-index:1050;padding:16px; }
        .kpi-modal-box { width:100%;max-width:680px;background:var(--sb-white);border-radius:18px;box-shadow:0 20px 56px rgba(0,0,0,0.15);overflow:hidden; }
        .kpi-modal-header { padding:16px 22px 14px;border-bottom:1px solid var(--sb-border);display:flex;align-items:center;justify-content:space-between; }
        .kpi-modal-body   { padding:16px 22px;display:grid;grid-template-columns:1fr 1fr;gap:16px;max-height:72vh;overflow-y:auto; }
        .kpi-modal-footer { padding:12px 22px;border-top:1px solid var(--sb-border);display:flex;justify-content:flex-end;gap:8px; }
        .field-label { font-size:0.67rem;font-weight:700;letter-spacing:0.8px;text-transform:uppercase;color:var(--sb-muted);margin-bottom:4px;display:block; }
        .field-input { width:100%;background:var(--sb-light-bg);border:1px solid var(--sb-border);border-radius:8px;padding:7px 11px;color:var(--sb-text);font-size:0.85rem;outline:none;font-family:inherit;transition:border-color 0.2s; }
        .field-input:focus { border-color:var(--sb-accent);background:var(--sb-white); }
        .field-input.err  { border-color:#e53e3e; }
        .field-select { width:100%;background:var(--sb-light-bg);border:1px solid var(--sb-border);border-radius:8px;padding:7px 11px;color:var(--sb-text);font-size:0.85rem;outline:none;font-family:inherit;transition:border-color 0.2s;cursor:pointer; }
        .field-select:focus { border-color:var(--sb-accent);background:var(--sb-white); }
        .kpi-search-input { background:var(--sb-light-bg);border:1px solid var(--sb-border);border-radius:50px;padding:7px 14px 7px 34px;color:var(--sb-text);font-size:0.83rem;outline:none;width:200px;transition:border-color 0.2s; }
        .kpi-search-input:focus { border-color:var(--sb-accent);background:var(--sb-white); }
        .formula-display-box { background:var(--sb-light-bg);border-radius:8px;padding:8px 12px;min-height:42px;font-family:monospace;font-size:0.85rem;color:var(--sb-text);word-break:break-all;display:flex;align-items:center;gap:6px;flex-wrap:wrap;cursor:pointer;transition:border-color 0.2s,background 0.2s,box-shadow 0.15s;position:relative;border:1.5px solid var(--sb-border); }
        .formula-display-box:hover  { border-color:var(--sb-accent);box-shadow:0 0 0 3px rgba(0,198,174,0.08); }
        .formula-display-box.active { border-color:var(--sb-accent);background:var(--sb-white);box-shadow:0 0 0 3px rgba(0,198,174,0.10); }
        .formula-display-box.err    { border-color:#e53e3e; }
        .calc-popup { animation:calcSlideIn 0.15s ease; }
        .calc-btn:hover { filter:brightness(0.93);transform:scale(0.97); }
        .freq-pill { padding:4px 9px;border-radius:20px;font-size:0.7rem;font-weight:700;border:1px solid var(--sb-border);background:var(--sb-light-bg);color:var(--sb-muted);cursor:pointer;transition:all 0.15s;white-space:nowrap; }
        .freq-pill.active { background:var(--sb-accent);color:#fff;border-color:var(--sb-accent); }
        .freq-pill:hover:not(.active) { border-color:var(--sb-accent);color:var(--sb-accent); }
        .spinning { animation:spin 0.9s linear infinite; }
      `}</style>

      {/* ── Page Header ───────────────────────────────────────────────────── */}
      <div className="sb-page-header px-4 py-3 mb-4">
        <div className="d-flex align-items-center justify-content-between flex-wrap gap-2">
          <div>
            <h5 className="sb-header-title mb-1"><i className="bi bi-graph-up-arrow me-2 sb-accent" />KPI Management</h5>
            <p className="sb-header-subtitle mb-0">Live KPIs — auto-refreshed at selected frequency from backend.</p>
          </div>

          <div className="d-flex align-items-center gap-2 flex-wrap">
            {/* Search */}
            <div style={{ position:"relative" }}>
              <i className="bi bi-search" style={{ position:"absolute", left:11, top:"50%", transform:"translateY(-50%)", color:"var(--sb-muted)", fontSize:"0.83rem" }} />
              <input type="text" className="kpi-search-input" placeholder="Search KPIs…" value={kpiSearch} onChange={(e) => setKpiSearch(e.target.value)} />
            </div>

            {/* ── Frequency selector ──────────────────────────────────────
                Selecting a pill updates `refreshFreq`.
                The useEffect below picks up the change, clears the old
                1-second interval and starts a fresh one with the new
                totalSecs. The countdown resets to the new value immediately.
            */}
            <div style={{ display:"flex", alignItems:"center", gap:5, padding:"5px 10px", border:"1px solid var(--sb-border)", borderRadius:50, background:"var(--sb-light-bg)" }}>
              <i className="bi bi-clock" style={{ fontSize:"0.75rem", color:"var(--sb-muted)" }} />
              <span style={{ fontSize:"0.68rem", color:"var(--sb-muted)", fontWeight:700, whiteSpace:"nowrap" }}>Refresh:</span>
              <div style={{ display:"flex", gap:3, flexWrap:"wrap" }}>
                {FREQUENCIES.map((f) => (
                  <button key={f} className={`freq-pill${refreshFreq===f?" active":""}`} onClick={() => setRefreshFreq(f)}>{f}</button>
                ))}
              </div>
            </div>

            {/* ── Live countdown + status ──────────────────────────────────
                Counts down to 0 then auto-fetches new values from backend.
                isRefreshing = true while API calls are in flight.
            */}
            <div style={{ display:"flex", alignItems:"center", gap:7, padding:"6px 13px", borderRadius:50, background:"var(--sb-light-bg)", border:"1px solid var(--sb-border)", fontSize:"0.75rem", color:"var(--sb-muted)", whiteSpace:"nowrap" }}>
              {isRefreshing ? (
                <>
                  <i className="bi bi-arrow-repeat spinning" style={{ color:"var(--sb-accent)", fontSize:"0.85rem" }} />
                  <span style={{ color:"var(--sb-accent)", fontWeight:700 }}>Refreshing…</span>
                </>
              ) : (
                <>
                  <span style={{ width:7, height:7, borderRadius:"50%", background:"#00c6ae", display:"inline-block", animation:"pulseDot 2s infinite", flexShrink:0 }} />
                  <span>Next in <strong style={{ color:"var(--sb-text)" }}>{countdown !== null ? formatCountdown(countdown) : "—"}</strong></span>
                </>
              )}
            </div>

            {/* Manual refresh button */}
            <button title="Refresh now" onClick={refreshLatestValues} disabled={isRefreshing}
              style={{ width:34, height:34, borderRadius:"50%", border:"1px solid var(--sb-border)", background:"var(--sb-light-bg)", color:"var(--sb-muted)", cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", transition:"all 0.15s" }}>
              <i className={`bi bi-arrow-clockwise${isRefreshing?" spinning":""}`} style={{ fontSize:"0.9rem" }} />
            </button>

            {/* Add KPI */}
            <button className="btn sb-connect-btn d-flex align-items-center gap-2" style={{ borderRadius:"50px", padding:"7px 20px", fontWeight:600 }} onClick={() => setShowForm(true)}>
              <i className="bi bi-plus-circle-fill" />Add KPI
            </button>
          </div>
        </div>
      </div>

      {/* Toasts */}
      {(successMsg || errMsg) && (
        <div className="position-fixed top-0 end-0 m-4" style={{ zIndex:9999 }}>
          {successMsg && <div className="alert alert-success shadow border-0 d-flex align-items-center gap-2"><i className="bi bi-check-circle-fill" />{successMsg}</div>}
          {errMsg     && <div className="alert alert-danger  shadow border-0 d-flex align-items-center gap-2"><i className="bi bi-exclamation-circle-fill" />{errMsg}</div>}
        </div>
      )}

      {/* ── KPI Cards ─────────────────────────────────────────────────────── */}
      <div className="container-fluid px-4">
        {loadingKpis ? (
          <div className="text-center py-5"><div className="spinner-border" style={{ color:"var(--sb-accent)" }} /><p className="mt-2 text-muted small">Loading KPIs…</p></div>
        ) : kpis.length === 0 ? (
          <div className="text-center py-5" style={{ color:"var(--sb-muted)" }}><i className="bi bi-graph-up" style={{ fontSize:"2.5rem" }} /><p className="mt-2">No KPIs configured yet. Click <strong>Add KPI</strong> to create your first one.</p></div>
        ) : filteredKpis.length === 0 ? (
          <div className="text-center py-5" style={{ color:"var(--sb-muted)" }}><i className="bi bi-search" style={{ fontSize:"2rem" }} /><p className="mt-2">No KPIs match <strong>"{kpiSearch}"</strong>.</p></div>
        ) : (
          <div className="row g-3">
            {filteredKpis.map((kpi) => (
              <div className="col-12 col-sm-6 col-lg-4 col-xl-3" key={kpi.id}>
                <KPICard kpi={kpi} lastRefreshed={lastRefreshed} isRefreshing={isRefreshing} />
              </div>
            ))}
          </div>
        )}
      </div>

      {/* ── Add KPI Modal ─────────────────────────────────────────────────── */}
      {showForm && (
        <div className="kpi-modal-overlay">
          <div className="kpi-modal-box">
            <div className="kpi-modal-header">
              <div>
                <h5 style={{ margin:0, fontWeight:700, color:"var(--sb-text)", fontSize:"1rem" }}><i className="bi bi-function me-2" style={{ color:"var(--sb-accent)" }} />New KPI Formula</h5>
                <p style={{ margin:0, fontSize:"0.72rem", color:"var(--sb-muted)", marginTop:2 }}>Build a formula using functions and sensor variables</p>
              </div>
              <button className="btn-close" onClick={() => { setShowForm(false); setErrors({}); setShowCalc(false); }} />
            </div>

            <div className="kpi-modal-body">
              {/* LEFT */}
              <div>
                <div className="d-flex gap-2 mb-3">
                  <div style={{ flex:2 }}>
                    <label className="field-label">KPI Name *</label>
                    <input className={`field-input ${errors.name?"err":""}`} placeholder="e.g. Machine Efficiency" value={form.name} onChange={(e) => { setForm((f)=>({...f,name:e.target.value})); setErrors((v)=>({...v,name:""})); }} />
                    {errors.name && <p style={{ fontSize:"0.66rem", color:"#e53e3e", margin:"3px 0 0" }}>{errors.name}</p>}
                  </div>
                  <div style={{ flex:1 }}>
                    <label className="field-label">Unit</label>
                    <input className="field-input" placeholder="%, hrs" value={form.unit} onChange={(e) => setForm((f)=>({...f,unit:e.target.value}))} />
                  </div>
                </div>

                <div className="mb-3">
                  <label className="field-label">Frequency</label>
                  <select className="field-select" value={form.frequency} onChange={(e) => setForm((f)=>({...f,frequency:e.target.value}))}>
                    {FREQUENCIES.map((freq) => <option key={freq} value={freq}>{freq}</option>)}
                  </select>
                </div>

                <div className="mb-3">
                  <label className="field-label">Functions</label>
                  <div className="d-flex gap-1 flex-wrap">
                    {FX_FUNCS.map((fn) => <button key={fn} type="button" className="fn-btn" onClick={() => insertFunction(fn)}>{fn}()</button>)}
                    <button type="button" className="fn-btn" style={{ color:"#0f8fd4", borderColor:"rgba(15,143,212,0.3)", background:"rgba(15,143,212,0.07)" }} onClick={() => insertToFormula(")")}>close )</button>
                  </div>
                </div>

                <div className="mb-2">
                  <label className="field-label">Formula *</label>
                  <div style={{ position:"relative" }}>
                    <div className={`formula-display-box ${showCalc?"active":""} ${errors.formula?"err":""}`} onClick={() => setShowCalc((v)=>!v)} title="Click to open calculator">
                      <span style={{ fontSize:"0.68rem", fontWeight:800, padding:"1px 6px", borderRadius:5, background:"var(--sb-accent)", color:"#fff", flexShrink:0 }}>fx</span>
                      <span style={{ flex:1, color:form.formula?"var(--sb-text)":"var(--sb-muted)", fontStyle:form.formula?"normal":"italic", fontSize:"0.82rem" }}>{form.formula||"Click to open calculator…"}</span>
                      <span style={{ color:"var(--sb-accent)", fontSize:"0.78rem", flexShrink:0 }}><i className={`bi bi-${showCalc?"chevron-up":"calculator"}`} /></span>
                      {form.formula && <button type="button" onClick={(e)=>{e.stopPropagation();setForm((f)=>({...f,formula:""}));setErrors((er)=>({...er,formula:""}));}} style={{ background:"none", border:"none", cursor:"pointer", color:"var(--sb-muted)", fontSize:13, lineHeight:1, padding:"1px 3px", borderRadius:4 }} title="Clear"><i className="bi bi-x-circle" /></button>}
                    </div>

                    {showCalc && (
                      <div style={{ position:"fixed", inset:0, zIndex:5000, display:"flex", alignItems:"center", justifyContent:"center", background:"rgba(0,0,0,0.25)" }} onClick={(e)=>{e.stopPropagation();setShowCalc(false);}}>
                        <div className="calc-popup" style={{ background:"var(--sb-white)", border:"1.5px solid var(--sb-border)", borderRadius:16, padding:14, boxShadow:"0 20px 56px rgba(0,0,0,0.18)", width:220 }} onClick={(e)=>e.stopPropagation()}>
                          <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:8 }}>
                            <span style={{ fontSize:"0.65rem", fontWeight:700, color:"var(--sb-muted)", textTransform:"uppercase", letterSpacing:"0.6px" }}>Calculator</span>
                            <button onClick={(e)=>{e.stopPropagation();setShowCalc(false);}} style={{ background:"none", border:"none", cursor:"pointer", color:"var(--sb-muted)", fontSize:14, lineHeight:1, padding:"2px 4px", borderRadius:4 }}>×</button>
                          </div>
                          <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:5 }}>
                            {[{l:"7",v:"7",t:"num"},{l:"8",v:"8",t:"num"},{l:"9",v:"9",t:"num"},{l:"+",v:" + ",t:"op"},{l:"4",v:"4",t:"num"},{l:"5",v:"5",t:"num"},{l:"6",v:"6",t:"num"},{l:"−",v:" - ",t:"op"},{l:"1",v:"1",t:"num"},{l:"2",v:"2",t:"num"},{l:"3",v:"3",t:"num"},{l:"×",v:" * ",t:"op"},{l:"(",v:"(",t:"bracket"},{l:"0",v:"0",t:"num"},{l:")",v:")",t:"bracket"},{l:"÷",v:" / ",t:"op"},{l:".",v:".",t:"num"},{l:"00",v:"00",t:"num"}].map(({l,v,t})=>(
                              <button key={l} type="button" className="calc-btn" onClick={(e)=>{e.stopPropagation();insertToFormula(v);}}
                                style={{ height:34, borderRadius:7, border:"1px solid", fontSize:t==="num"?"0.86rem":"0.9rem", fontWeight:t==="op"?800:600, cursor:"pointer", transition:"all 0.1s",
                                  ...(t==="op"?{background:"rgba(0,198,174,0.10)",borderColor:"rgba(0,198,174,0.3)",color:"var(--sb-accent)"}:t==="bracket"?{background:"rgba(15,143,212,0.08)",borderColor:"rgba(15,143,212,0.25)",color:"#0f8fd4"}:{background:"var(--sb-light-bg)",borderColor:"var(--sb-border)",color:"var(--sb-text)"})}}>{l}</button>
                            ))}
                            <button type="button" className="calc-btn" onClick={(e)=>{e.stopPropagation();backspaceFormula();}} style={{ gridColumn:"span 2", height:34, borderRadius:7, border:"1px solid #e53e3e44", background:"rgba(229,62,62,0.07)", color:"#e53e3e", fontWeight:700, fontSize:"0.76rem", cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", gap:4, transition:"all 0.1s" }}>
                              <i className="bi bi-backspace" style={{ fontSize:"0.82rem" }} /> Del
                            </button>
                          </div>
                        </div>
                      </div>
                    )}
                  </div>
                </div>

                {errors.formula && <p style={{ fontSize:"0.66rem", color:"#e53e3e", margin:"3px 0 6px" }}><i className="bi bi-exclamation-triangle me-1" />{errors.formula}</p>}
                {form.formula.trim() && <div style={{ marginTop:4, padding:"6px 10px", background:"rgba(0,198,174,0.07)", borderRadius:7, fontSize:"0.76rem", border:"1px solid #00c6ae35", display:"flex", alignItems:"center", gap:5 }}><i className="bi bi-info-circle" style={{ color:"#00c6ae" }} />KPI will be calculated from real sensor data after creation</div>}

                <div className="d-flex gap-2 mt-3">
                  <div style={{ flex:1 }}>
                    <label className="field-label">Color</label>
                    <input type="color" className="field-input p-1" value={form.color} onChange={(e)=>setForm((f)=>({...f,color:e.target.value}))} style={{ height:"35px" }} />
                  </div>
                  <div style={{ flex:2 }}>
                    <label className="field-label">Icon class</label>
                    <input className="field-input" placeholder="bi-graph-up" value={form.icon} onChange={(e)=>setForm((f)=>({...f,icon:e.target.value}))} />
                  </div>
                </div>
              </div>

              {/* RIGHT — sensors */}
              <div style={{ borderLeft:"1px solid var(--sb-border)", paddingLeft:16 }}>
                <label className="field-label">Sensor Variables</label>
                <p style={{ fontSize:"0.71rem", color:"var(--sb-muted)", marginBottom:8, lineHeight:1.4 }}>
                  Click a sensor to insert its variable.<br />
                  <span style={{ color:"var(--sb-accent)", fontWeight:600 }}>Tip:</span> function → sensor → <code>)</code>
                </p>
                <div className="fx-bar mb-2" style={{ padding:"5px 10px" }}>
                  <i className="bi bi-search me-2" style={{ color:"var(--sb-muted)", fontSize:"0.78rem" }} />
                  <input placeholder="Search sensors…" value={sensorSearch} onChange={(e)=>setSensorSearch(e.target.value)} style={{ flex:1, background:"none", border:"none", outline:"none", fontSize:"0.81rem", color:"var(--sb-text)" }} />
                </div>
                <div style={{ display:"flex", flexWrap:"wrap", gap:5, maxHeight:"230px", overflowY:"auto" }}>
                  {filteredSensors.length===0 ? (
                    <p style={{ fontSize:"0.76rem", color:"var(--sb-muted)", width:"100%", textAlign:"center", paddingTop:16 }}>
                      <i className="bi bi-broadcast me-1" />{sensors.length===0?"No sensors connected.":"No sensors match your search."}
                    </p>
                  ) : filteredSensors.map((s)=>(
                    <button key={s.id} type="button" className="sensor-chip" onClick={()=>insertToFormula(`sensor_${s.id}`)}>
                      <i className="bi bi-broadcast" style={{ fontSize:"0.62rem", color:"var(--sb-accent)" }} />
                      sensor_{s.id}
                      {s.name&&<span style={{ opacity:0.6, fontSize:"0.68rem" }}>· {s.name}</span>}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            <div className="kpi-modal-footer">
              <button style={{ padding:"7px 18px", borderRadius:"8px", border:"1.5px solid var(--sb-border)", background:"none", color:"var(--sb-text)", fontWeight:600, cursor:"pointer", fontSize:"0.87rem" }} onClick={()=>{setShowForm(false);setErrors({});setShowCalc(false);}}>Cancel</button>
              <button className="btn sb-connect-btn" style={{ borderRadius:"8px", padding:"7px 20px", fontWeight:600, fontSize:"0.87rem" }} onClick={handleAddKpi} disabled={saving}>
                {saving?<><span className="spinner-border spinner-border-sm me-2" />Saving…</>:<><i className="bi bi-plus-circle me-2" />Add KPI</>}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default KPIManagement;
